```java
import java.util.*;

public class Solution {
    public static long solve(String s, long[] order, long k) {
        int n = s.length();
        int[] positions = new int[n];
        for (int i = 0; i < n; i++) {
            positions[order[i]] = i;
        }

        long[] cnt = new long[n + 1];
        for (int i = 0; i < n; i++) {
            int pos = positions[i];
            int left = pos;
            while (left >= 0 && s.charAt(left) != '*') {
                left--;
            }
            int right = pos;
            while (right < n && s.charAt(right) != '*') {
                right++;
            }
            int len = right - left - 1;
            cnt[len + 1]++;
            for (int l = 1; l <= len; l++) {
                cnt[l]++;
            }
        }

        long res = -1;
        for (int t = 0; t < n; t++) {
            int pos = positions[t];
            int left = pos;
            while (left >= 0 && s.charAt(left) != '*') {
                left--;
            }
            int right = pos;
            while (right < n && s.charAt(right) != '*') {
                right++;
            }
            int len = right - left - 1;
            long total = 0;
            for (int l = 1; l <= len; l++) {
                total += cnt[l];
            }
            if (total >= k) {
                res = t;
                break;
            }
        }
        return res;
    }
}
