public static long solve(String s, long[] order, long k) {
    int n = s.length();
    boolean[] replaced = new boolean[n];
    long[] prefix = new long[n + 1];

    // Precompute the number of '*' in the first i characters
    for (int i = 0; i < n; i++) {
        prefix[i + 1] = prefix[i] + (s.charAt(i) == '*' ? 1 : 0);
    }

    // For each position in order, simulate replacing the character and calculate the number of valid substrings
    for (int t = 0; t < n; t++) {
        int idx = (int) order[t];
        if (replaced[idx]) continue; // Skip if already replaced

        replaced[idx] = true;
        // Calculate the number of valid substrings after this replacement
        long count = 0;
        for (int i = 0; i < n; i++) {
            int left = i;
            while (left >= 0 && s.charAt(left) != '*') {
                left--;
            }
            if (left >= 0) {
                int right = i;
                while (right < n && s.charAt(right) != '*') {
                    right++;
                }
                if (right < n) {
                    count += (right - left) * (right - left + 1) / 2;
                }
            }
        }

        if (count >= k) {
            return t;
        }
    }

    return -1;
}
