```java
import java.util.*;

public class Solution {
    public static long solve(String s, long[] order, long k) {
        int n = s.length();
        int[] positions = new int[n];
        for (int i = 0; i < n; i++) {
            positions[i] = order[i];
        }

        // We will keep track of the number of '*' added at each step
        long[] starCount = new long[n];
        Arrays.fill(starCount, 0);

        // We will keep track of the number of valid substrings at each step
        long[] validSubstrings = new long[n];
        Arrays.fill(validSubstrings, 0);

        // Precompute the number of valid substrings for each possible t
        for (int t = 0; t < n; t++) {
            int pos = positions[t];
            starCount[pos]++;

            // Calculate the number of valid substrings that include the current position
            int left = pos;
            while (left >= 0 && starCount[left] > 0) {
                left--;
            }
            int right = pos;
            while (right < n && starCount[right] > 0) {
                right++;
            }

            int leftCount = pos - left;
            int rightCount = right - pos;
            long newValid = leftCount * rightCount;

            validSubstrings[t] = validSubstrings[t - 1] + newValid;

            if (validSubstrings[t] >= k) {
                return t;
            }
        }

        return -1;
    }
}
