```java
import java.util.*;

public class Solution {
    public static long solve(String s, long[] order, long k) {
        int n = s.length();
        int[] positions = new int[n];
        for (int i = 0; i < n; i++) {
            positions[order[i]] = i;
        }

        long[] prefix = new long[n + 1];
        for (int i = 0; i < n; i++) {
            prefix[i + 1] = prefix[i] + (positions[i] == -1 ? 0 : 1);
        }

        long[] suffix = new long[n + 1];
        for (int i = n - 1; i >= 0; i--) {
            suffix[i] = suffix[i + 1] + (positions[i] == -1 ? 0 : 1);
        }

        long total = 0;
        for (int i = 0; i < n; i++) {
            if (positions[i] != -1) {
                total += (i + 1) * (n - i);
            }
        }

        if (total < k) {
            return -1;
        }

        long ans = -1;
        for (int t = 0; t < n; t++) {
            int pos = order[t];
            positions[pos] = -1;

            long count = 0;
            for (int i = 0; i < n; i++) {
                if (positions[i] != -1) {
                    count += (i + 1) * (n - i);
                }
            }

            if (count >= k) {
                ans = t;
                break;
            }
        }

        return ans;
    }
}
